import json

class CustomObject:
    def __init__(self, **kwargs):
        self.__dict__.update(kwargs)

def save_preferences(preferences, file_path):
    with open(file_path, 'w') as f:
        json.dump(preferences.__dict__, f, default=lambda o: o.__dict__ if hasattr(o, '__dict__') else str(o))

def load_preferences(file_path):
    with open(file_path, 'r') as f:
        preferences = {}
        obj = type({})
        preferences.__class__ = obj
        preferences = json.load(f, object_hook=lambda d: obj(__dict__=d))
    return preferences